SELECT count(*) FROM supplier_onboarding

    AND supplier_id = #{supplierId}
    AND business_type = #{businessType}
    AND state_id = #{stateId}
    AND applicant_name LIKE CONCAT('%', #{applicantName}, '%')
    AND business_name LIKE CONCAT('%', #{businessName}, '%')

SELECT id as "id", supplier_id as "supplierId", applicant_name as "applicantName", business_name as "businessName", business_type as "businessType", training_progress as "trainingProgress", state_id as "stateId", flow_id as "flowId", submitted_at as "submittedAt", created_time as "createdTime" FROM supplier_onboarding
AND supplier_id = #{supplierId} AND business_type = #{businessType} AND state_id = #{stateId} AND applicant_name LIKE CONCAT('%', #{applicantName}, '%') AND business_name LIKE CONCAT('%', #{businessName}, '%')
${orderby} ${pagination}
